module top (
  input clk,
  output reg c = 1'b0
);

  reg a = 1'b0;
  always @(posedge clk)
    a <= !a;

  wire [2:0] b = 3'd3 + { 2'b0, a };

  always @(posedge clk)
    if (b == 3'd0) c <= 1'b1;

endmodule

module top (
  input clk,
  output reg c = 1'b0
);

  reg [1:0] a = 2'd0;
  always @(posedge clk)
    a <= a + 1;

  wire [4:0] b = 5'd13 + { 3'b0, a };

  always @(posedge clk)
    if (b == 5'd0) c <= 1'b1;

endmodule
